using Godot; public partial class CameraFeedbackController : Node { [Export] public Camera2D TargetCamera{get;set;} [Export] public float ShakeReturnSpeed{get;set;}=16f; private Vector2 _shakeOffset; public override void _Process(double delta){ if(TargetCamera==null)return; _shakeOffset=_shakeOffset.Lerp(Vector2.Zero,ShakeReturnSpeed*(float)delta); TargetCamera.Offset=_shakeOffset;} public void Shake(float power){_shakeOffset=new Vector2(power,-power*0.6f);} }